//! Behavior-pinning batch AS (2026-05-06): `$a` and `$b` are exempt from
//! `use strict 'vars'` because Perl predefines them as the sort/reduce
//! comparator slots (package globals `$main::a`, `$main::b`).
//!
//! Pre-fix, stryke's compile-time strict-vars check rejected any reference
//! to `$a` or `$b` outside an explicit `my`/`our` declaration:
//!
//!   $ stryke -e 'use strict; my @x = sort { $a <=> $b } 3,1,2'
//!   Global symbol "$b" requires explicit package name (did you forget to
//!   declare "my $b"?) at -e line 1.
//!
//! That broke ~46 parity cases generated by the parity harness, which all
//! end with a `sort { length($b) <=> length($a) }` line under `use strict`.
//! Perl exempts these names unconditionally — adding them to
//! `VMHelper::strict_scalar_exempt` matches Perl's behavior.

use crate::common::*;

#[test]
fn strict_sort_numeric_compiles() {
    // The exact pattern from parity case 10093_p5.pl line 61.
    let code = r#"
        use strict;
        my @x = sort { $a <=> $b } (3, 1, 2);
        join(",", @x)
    "#;
    assert_eq!(eval_string(code), "1,2,3");
}

#[test]
fn strict_sort_descending_strcmp_compiles() {
    // `sort { $b cmp $a }` — descending strcmp under strict.
    let code = r#"
        use strict;
        my @x = sort { $b cmp $a } qw/zz yy xx/;
        join(",", @x)
    "#;
    assert_eq!(eval_string(code), "zz,yy,xx");
}

#[test]
fn strict_sort_length_compare_compiles() {
    // `sort { length($b) <=> length($a) }` — the failing tail of the
    // 10000-series parity cases.
    let code = r#"
        use strict;
        my @x = sort { length($b) <=> length($a) } qw/x xx xxx/;
        join(",", @x)
    "#;
    assert_eq!(eval_string(code), "xxx,xx,x");
}

#[test]
fn strict_bare_a_b_reference_compiles() {
    // Perl's exemption is unconditional — even outside a sort block, bare
    // `$a` / `$b` references are exempt because they are predeclared
    // package globals. Mirror that: stryke must not reject the reference,
    // only return their (undefined) values.
    let code = r#"
        use strict;
        my $sum = ($a // 0) + ($b // 0);
        $sum
    "#;
    assert_eq!(eval_int(code), 0);
}

#[test]
fn strict_other_single_letter_still_rejected() {
    // Sanity check: only `$a` and `$b` are exempt — `$c`, `$d`, etc.
    // still trip strict-vars.
    let code = r#"
        use strict;
        print $c;
    "#;
    let err = eval_err_kind(code);
    // Should be a compile-time strict-vars failure; just confirm it errored.
    assert_ne!(format!("{:?}", err), "");
}
